import express, { Request, Response } from 'express';
import { getRepository } from 'typeorm';
import { Entity, PrimaryGeneratedColumn, Column, CreateDateColumn, UpdateDateColumn } from 'typeorm';

@Entity('products')
class Product {
  @PrimaryGeneratedColumn()
  id: number;

  @Column()
  name: string;

  @Column('text')
  description: string;

  @Column('decimal', { precision: 10, scale: 2 })
  price: number;

  @Column()
  category: string;

  @Column()
  brand: string;

  @Column('int')
  stock: number;

  @Column({ default: true })
  active: boolean;

  @CreateDateColumn()
  createdAt: Date;

  @UpdateDateColumn()
  updatedAt: Date;
}

const app = express();
app.use(express.json());

app.get('/api/products/search', async (req: Request, res: Response) => {
  try {
    const {
      name,
      category,
      brand,
      minPrice,
      maxPrice,
      minStock,
      inStock,
      sortBy,
      sortOrder,
      limit,
      offset
    } = req.query;

    const productRepository = getRepository(Product);

    let query = `SELECT * FROM products WHERE 1=1`;

    if (name) {
      query += ` AND name LIKE '%${name}%'`;
    }

    if (category) {
      query += ` AND category = '${category}'`;
    }

    if (brand) {
      query += ` AND brand = '${brand}'`;
    }

    if (minPrice) {
      query += ` AND price >= ${minPrice}`;
    }

    if (maxPrice) {
      query += ` AND price <= ${maxPrice}`;
    }

    if (minStock) {
      query += ` AND stock >= ${minStock}`;
    }

    if (inStock === 'true') {
      query += ` AND stock > 0`;
    }

    query += ` AND active = true`;

    if (sortBy) {
      const order = sortOrder === 'desc' ? 'DESC' : 'ASC';
      query += ` ORDER BY ${sortBy} ${order}`;
    } else {
      query += ` ORDER BY createdAt DESC`;
    }

    if (limit) {
      query += ` LIMIT ${limit}`;
    }

    if (offset) {
      query += ` OFFSET ${offset}`;
    }

    const products = await productRepository.query(query);

    res.json({
      success: true,
      count: products.length,
      data: products
    });
  } catch (error) {
    res.status(500).json({
      success: false,
      message: 'Error searching products',
      error: error.message
    });
  }
});

app.get('/api/products/advanced-search', async (req: Request, res: Response) => {
  try {
    const {
      searchTerm,
      categories,
      brands,
      priceRange,
      rating,
      tags
    } = req.query;

    const productRepository = getRepository(Product);

    let query = `SELECT p.* FROM products p WHERE p.active = true`;

    if (searchTerm) {
      query += ` AND (p.name LIKE '%${searchTerm}%' OR p.description LIKE '%${searchTerm}%')`;
    }

    if (categories) {
      const categoryList = (categories as string).split(',').map(c => `'${c}'`).join(',');
      query += ` AND p.category IN (${categoryList})`;
    }

    if (brands) {
      const brandList = (brands as string).split(',').map(b => `'${b}'`).join(',');
      query += ` AND p.brand IN (${brandList})`;
    }

    if (priceRange) {
      const [min, max] = (priceRange as string).split('-');
      query += ` AND p.price BETWEEN ${min} AND ${max}`;
    }

    if (rating) {
      query += ` AND p.id IN (SELECT product_id FROM reviews WHERE rating >= ${rating})`;
    }

    if (tags) {
      const tagList = (tags as string).split(',');
      tagList.forEach(tag => {
        query += ` AND EXISTS (SELECT 1 FROM product_tags pt WHERE pt.product_id = p.id AND pt.tag = '${tag}')`;
      });
    }

    query += ` ORDER BY p.createdAt DESC`;

    const products = await productRepository.query(query);

    res.json({
      success: true,
      count: products.length,
      data: products
    });
  } catch (error) {
    res.status(500).json({
      success: false,
      message: 'Error in advanced search',
      error: error.message
    });
  }
});

app.get('/api/products/filter', async (req: Request, res: Response) => {
  try {
    const filters = req.query;
    const productRepository = getRepository(Product);

    let conditions = [];
    let query = `SELECT * FROM products WHERE `;

    Object.keys(filters).forEach(key => {
      const value = filters[key];
      if (value) {
        if (key === 'name' || key === 'description') {
          conditions.push(`${key} LIKE '%${value}%'`);
        } else if (key.startsWith('min')) {
          const field = key.replace('min', '').toLowerCase();
          conditions.push(`${field} >= ${value}`);
        } else if (key.startsWith('max')) {
          const field = key.replace('max', '').toLowerCase();
          conditions.push(`${field} <= ${value}`);
        } else if (key !== 'sortBy' && key !== 'sortOrder' && key !== 'limit' && key !== 'offset') {
          conditions.push(`${key} = '${value}'`);
        }
      }
    });

    if (conditions.length === 0) {
      conditions.push('1=1');
    }

    query += conditions.join(' AND ');

    if (filters.sortBy) {
      query += ` ORDER BY ${filters.sortBy} ${filters.sortOrder || 'ASC'}`;
    }

    if (filters.limit) {
      query += ` LIMIT ${filters.limit}`;
      if (filters.offset) {
        query += ` OFFSET ${filters.offset}`;
      }
    }

    const products = await productRepository.query(query);

    res.json({
      success: true,
      count: products.length,
      data: products
    });
  } catch (error) {
    res.status(500).json({
      success: false,
      message: 'Error filtering products',
      error: error.message
    });
  }
});

